import GRDB

/// Hard Gate後の通信実装とは独立した、同期ローカル台帳のv3物理schemaです。
enum SyncPersistenceSchema {
    /// Vehicle／Acquisition schemaへ追記するMigration識別子です。
    nonisolated static let v3MigrationIdentifier = "v3_create_local_sync_state"

    /// 18テーブル、保全Trigger、9つのactive-or-local Viewを作成するSQLです。
    nonisolated static let v3SQL = """
    CREATE TABLE local_device_identity (
      scope_row_id INTEGER PRIMARY KEY CHECK(scope_row_id = 1),
      user_scope_id TEXT NOT NULL UNIQUE CHECK(length(user_scope_id) = 36),
      device_identity_id TEXT NOT NULL UNIQUE CHECK(length(device_identity_id) = 36),
      device_role TEXT NOT NULL CHECK(device_role IN ('iphone','mac')),
      device_identity_version INTEGER NOT NULL CHECK(device_identity_version >= 1),
      signing_key_version INTEGER NOT NULL CHECK(signing_key_version >= 1),
      signing_public_key BLOB NOT NULL CHECK(length(signing_public_key) > 0),
      signing_key_fingerprint BLOB NOT NULL UNIQUE CHECK(length(signing_key_fingerprint) = 32),
      signing_keychain_reference_id TEXT NOT NULL UNIQUE CHECK(length(signing_keychain_reference_id) = 36),
      key_agreement_key_version INTEGER NOT NULL CHECK(key_agreement_key_version >= 1),
      key_agreement_public_key BLOB NOT NULL CHECK(length(key_agreement_public_key) > 0),
      key_agreement_key_fingerprint BLOB NOT NULL UNIQUE CHECK(length(key_agreement_key_fingerprint) = 32),
      key_agreement_keychain_reference_id TEXT NOT NULL UNIQUE CHECK(length(key_agreement_keychain_reference_id) = 36),
      tls_identity_key_version INTEGER NOT NULL CHECK(tls_identity_key_version >= 1),
      tls_identity_public_key BLOB NOT NULL CHECK(length(tls_identity_public_key) > 0),
      tls_identity_key_fingerprint BLOB NOT NULL UNIQUE CHECK(length(tls_identity_key_fingerprint) = 32),
      tls_certificate_fingerprint BLOB NOT NULL UNIQUE CHECK(length(tls_certificate_fingerprint) = 32),
      tls_identity_keychain_reference_id TEXT NOT NULL UNIQUE CHECK(length(tls_identity_keychain_reference_id) = 36),
      membership_state TEXT NOT NULL CHECK(membership_state IN ('unprovisioned','bootstrap_pending','established','blocked')),
      membership_version INTEGER,
      membership_credential_digest BLOB CHECK(membership_credential_digest IS NULL OR length(membership_credential_digest) = 32),
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL CHECK(length(created_by_device_id) = 36),
      updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL CHECK(length(updated_by_device_id) = 36), revision INTEGER NOT NULL CHECK(revision >= 1),
      FOREIGN KEY(scope_row_id) REFERENCES database_scope(scope_row_id) ON DELETE RESTRICT ON UPDATE RESTRICT,
      CHECK((membership_state = 'established' AND membership_version IS NOT NULL AND membership_version >= 1) OR (membership_state <> 'established' AND membership_version IS NULL AND membership_credential_digest IS NULL))
    ) STRICT;

    CREATE TABLE paired_devices (
      user_scope_id TEXT NOT NULL CHECK(length(user_scope_id) = 36), peer_identity_id TEXT NOT NULL CHECK(length(peer_identity_id) = 36),
      device_role TEXT NOT NULL CHECK(device_role IN ('iphone','mac')), device_identity_version INTEGER NOT NULL CHECK(device_identity_version >= 1),
      signing_key_version INTEGER NOT NULL CHECK(signing_key_version >= 1), signing_public_key BLOB NOT NULL, signing_key_fingerprint BLOB NOT NULL CHECK(length(signing_key_fingerprint)=32),
      key_agreement_key_version INTEGER NOT NULL CHECK(key_agreement_key_version >= 1), key_agreement_public_key BLOB NOT NULL, key_agreement_key_fingerprint BLOB NOT NULL CHECK(length(key_agreement_key_fingerprint)=32),
      tls_identity_key_version INTEGER NOT NULL CHECK(tls_identity_key_version >= 1), tls_identity_public_key BLOB NOT NULL, tls_identity_key_fingerprint BLOB NOT NULL CHECK(length(tls_identity_key_fingerprint)=32),
      tls_certificate_fingerprint BLOB NOT NULL CHECK(length(tls_certificate_fingerprint)=32), peer_pin_keychain_reference_id TEXT NOT NULL CHECK(length(peer_pin_keychain_reference_id)=36),
      membership_verification_state TEXT NOT NULL CHECK(membership_verification_state IN ('pending','verified','rejected')), membership_version INTEGER,
      pairing_state TEXT NOT NULL CHECK(pairing_state IN ('pending_local_confirmation','pending_peer_confirmation','paired','unpaired')), paired_at TEXT, unpaired_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision >= 1),
      PRIMARY KEY(user_scope_id,peer_identity_id),
      UNIQUE(user_scope_id,signing_key_fingerprint), UNIQUE(user_scope_id,key_agreement_key_fingerprint), UNIQUE(user_scope_id,tls_identity_key_fingerprint), UNIQUE(user_scope_id,tls_certificate_fingerprint), UNIQUE(user_scope_id,peer_pin_keychain_reference_id),
      CHECK((membership_verification_state='verified' AND membership_version IS NOT NULL AND membership_version>=1) OR (membership_verification_state<>'verified' AND membership_version IS NULL)),
      CHECK((pairing_state='paired' AND paired_at IS NOT NULL AND unpaired_at IS NULL) OR (pairing_state='unpaired' AND unpaired_at IS NOT NULL) OR (pairing_state IN ('pending_local_confirmation','pending_peer_confirmation') AND paired_at IS NULL AND unpaired_at IS NULL))
    ) STRICT;

    CREATE TABLE device_trust_records (
      user_scope_id TEXT NOT NULL, peer_identity_id TEXT NOT NULL, trust_state TEXT NOT NULL CHECK(trust_state IN ('trusted','suspended','revoked')), trust_generation INTEGER NOT NULL CHECK(trust_generation>=1),
      trusted_at TEXT NOT NULL, suspended_at TEXT, revoked_at TEXT, reason_code TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id) ON DELETE RESTRICT ON UPDATE RESTRICT,
      CHECK((trust_state='trusted' AND suspended_at IS NULL AND revoked_at IS NULL AND reason_code IS NULL) OR (trust_state='suspended' AND suspended_at IS NOT NULL AND revoked_at IS NULL AND reason_code IS NOT NULL) OR (trust_state='revoked' AND revoked_at IS NOT NULL AND suspended_at IS NULL AND reason_code IS NOT NULL))
    ) STRICT;

    CREATE TABLE primary_mac_assignments (
      user_scope_id TEXT NOT NULL, assignment_id TEXT NOT NULL CHECK(length(assignment_id)=36), iphone_identity_id TEXT NOT NULL CHECK(length(iphone_identity_id)=36), mac_identity_id TEXT NOT NULL CHECK(length(mac_identity_id)=36),
      assignment_state TEXT NOT NULL CHECK(assignment_state IN ('pending_confirmation','active','superseded','revoked')), activated_at TEXT, ended_at TEXT, previous_assignment_id TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,assignment_id), FOREIGN KEY(user_scope_id,previous_assignment_id) REFERENCES primary_mac_assignments(user_scope_id,assignment_id) DEFERRABLE INITIALLY DEFERRED,
      CHECK(iphone_identity_id<>mac_identity_id), CHECK(previous_assignment_id IS NULL OR previous_assignment_id<>assignment_id),
      CHECK((assignment_state='pending_confirmation' AND activated_at IS NULL AND ended_at IS NULL) OR (assignment_state='active' AND activated_at IS NOT NULL AND ended_at IS NULL) OR (assignment_state IN ('superseded','revoked') AND ended_at IS NOT NULL))
    ) STRICT;
    CREATE UNIQUE INDEX one_active_primary_mac_per_iphone ON primary_mac_assignments(user_scope_id,iphone_identity_id) WHERE assignment_state='active';

    CREATE TABLE logical_sync_changes (
      user_scope_id TEXT NOT NULL, logical_change_id TEXT NOT NULL CHECK(length(logical_change_id)=36), origin_device_identity_id TEXT NOT NULL CHECK(length(origin_device_identity_id)=36),
      origin_signing_key_version INTEGER NOT NULL CHECK(origin_signing_key_version>=1), origin_signing_public_key BLOB NOT NULL, origin_signing_key_fingerprint BLOB NOT NULL CHECK(length(origin_signing_key_fingerprint)=32),
      origin_change_id TEXT NOT NULL CHECK(length(origin_change_id)=36), stream_kind TEXT NOT NULL CHECK(stream_kind IN ('vehicle_display_name','vehicle_lifecycle','immutable_identity','session_log')), change_sequence INTEGER NOT NULL CHECK(change_sequence>=0),
      previous_change_id TEXT, previous_chain_digest BLOB CHECK(previous_chain_digest IS NULL OR length(previous_chain_digest)=32), chain_digest BLOB NOT NULL CHECK(length(chain_digest)=32),
      entity_kind TEXT NOT NULL, entity_id TEXT NOT NULL CHECK(length(entity_id)=36), origin_vehicle_id TEXT, origin_parent_entity_kind TEXT, origin_parent_entity_id TEXT, origin_secondary_parent_entity_kind TEXT, origin_secondary_parent_entity_id TEXT, origin_tertiary_parent_entity_kind TEXT, origin_tertiary_parent_entity_id TEXT,
      entity_schema_version INTEGER NOT NULL CHECK(entity_schema_version>=1), operation_kind TEXT NOT NULL CHECK(operation_kind IN ('upsert_immutable','upsert_field_revision')), base_revision INTEGER, result_revision INTEGER NOT NULL CHECK(result_revision>=1),
      content_digest BLOB NOT NULL CHECK(length(content_digest)=32), origin_envelope_ciphertext BLOB NOT NULL CHECK(length(origin_envelope_ciphertext)>0), origin_signature BLOB NOT NULL CHECK(length(origin_signature)>0), origin_membership_proof_digest BLOB NOT NULL CHECK(length(origin_membership_proof_digest)=32),
      creation_revision INTEGER NOT NULL CHECK(creation_revision=1), origin_created_at TEXT NOT NULL, created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL,
      PRIMARY KEY(user_scope_id,logical_change_id), UNIQUE(user_scope_id,origin_device_identity_id,origin_change_id), UNIQUE(user_scope_id,origin_device_identity_id,stream_kind,change_sequence),
      CHECK((change_sequence=0 AND previous_change_id IS NULL AND previous_chain_digest IS NULL) OR (change_sequence>0 AND previous_change_id IS NOT NULL AND previous_chain_digest IS NOT NULL)),
      CHECK((origin_parent_entity_kind IS NULL)=(origin_parent_entity_id IS NULL)), CHECK((origin_secondary_parent_entity_kind IS NULL)=(origin_secondary_parent_entity_id IS NULL)), CHECK((origin_tertiary_parent_entity_kind IS NULL)=(origin_tertiary_parent_entity_id IS NULL)),
      CHECK(origin_tertiary_parent_entity_id IS NULL OR origin_secondary_parent_entity_id IS NOT NULL),
      CHECK((operation_kind='upsert_immutable' AND base_revision IS NULL) OR (operation_kind='upsert_field_revision' AND base_revision IS NOT NULL AND result_revision=base_revision+1))
    ) STRICT;

    CREATE TABLE sync_batches (
      user_scope_id TEXT NOT NULL, batch_id TEXT NOT NULL CHECK(length(batch_id)=36), transfer_id TEXT NOT NULL CHECK(length(transfer_id)=36), peer_identity_id TEXT NOT NULL, direction TEXT NOT NULL CHECK(direction IN ('send','receive')),
      sync_protocol_version INTEGER NOT NULL CHECK(sync_protocol_version>=1), capability_digest BLOB NOT NULL CHECK(length(capability_digest)=32), batch_state TEXT NOT NULL CHECK(batch_state IN ('preparing','transferring','applying','waiting_ack','completed','retryable','blocked')),
      last_error_code TEXT, diagnostic_id TEXT, completed_at TEXT, created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,batch_id), UNIQUE(user_scope_id,peer_identity_id,transfer_id,direction), FOREIGN KEY(user_scope_id,peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id) ON DELETE RESTRICT ON UPDATE RESTRICT,
      CHECK((batch_state IN ('retryable','blocked'))=(last_error_code IS NOT NULL)), CHECK((last_error_code IS NULL)=(diagnostic_id IS NULL)), CHECK((batch_state='completed')=(completed_at IS NOT NULL))
    ) STRICT;

    CREATE TABLE sync_conflicts (
      user_scope_id TEXT NOT NULL, conflict_id TEXT NOT NULL CHECK(length(conflict_id)=36), source_peer_identity_id TEXT NOT NULL, logical_change_id TEXT NOT NULL,
      conflict_kind TEXT NOT NULL CHECK(conflict_kind IN ('immutable_entity_collision','vehicle_identity_ambiguous','vehicle_alias_collision','field_divergence')), entity_kind TEXT NOT NULL, entity_id TEXT NOT NULL, field_kind TEXT, base_revision INTEGER,
      conflict_state TEXT NOT NULL CHECK(conflict_state IN ('open','awaiting_user','resolved','acknowledged_unresolved')), resolution_revision INTEGER, resolved_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,conflict_id), FOREIGN KEY(user_scope_id,source_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,logical_change_id) REFERENCES logical_sync_changes(user_scope_id,logical_change_id),
      CHECK((conflict_kind='field_divergence' AND field_kind IN ('display_name','lifecycle_state') AND base_revision IS NOT NULL) OR (conflict_kind<>'field_divergence' AND field_kind IS NULL AND base_revision IS NULL)),
      CHECK((conflict_state='resolved')=(resolution_revision IS NOT NULL AND resolved_at IS NOT NULL))
    ) STRICT;

    CREATE TABLE sync_quarantine_items (
      user_scope_id TEXT NOT NULL, quarantine_id TEXT NOT NULL CHECK(length(quarantine_id)=36), source_peer_identity_id TEXT, batch_id TEXT, observed_message_type_code INTEGER NOT NULL CHECK(observed_message_type_code>=0), observed_protocol_version INTEGER NOT NULL CHECK(observed_protocol_version>=0), observed_entity_version INTEGER,
      reason_code TEXT NOT NULL CHECK(reason_code IN ('unknown_version','unknown_message_type','identity_mismatch','digest_mismatch','aead_failed','entity_collision','foreign_key_invalid','format_invalid')), payload_digest BLOB NOT NULL CHECK(length(payload_digest)=32), quarantine_relative_path TEXT NOT NULL,
      quarantine_state TEXT NOT NULL CHECK(quarantine_state IN ('isolated','retryable','reviewed','resolved')), diagnostic_id TEXT NOT NULL CHECK(length(diagnostic_id)=36), resolved_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,quarantine_id), FOREIGN KEY(user_scope_id,source_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,batch_id) REFERENCES sync_batches(user_scope_id,batch_id), CHECK((quarantine_state='resolved')=(resolved_at IS NOT NULL))
    ) STRICT;

    CREATE TABLE sync_change_deliveries (
      user_scope_id TEXT NOT NULL, delivery_id TEXT NOT NULL CHECK(length(delivery_id)=36), logical_change_id TEXT NOT NULL, target_peer_identity_id TEXT NOT NULL, relay_device_identity_id TEXT NOT NULL, relayed_from_peer_identity_id TEXT, relay_hop_count INTEGER NOT NULL CHECK(relay_hop_count>=0),
      delivery_state TEXT NOT NULL CHECK(delivery_state IN ('pending','in_batch','acked','retryable','blocked','suppressed')), batch_id TEXT, ack_id TEXT, acked_sequence INTEGER, acked_chain_digest BLOB, retry_count INTEGER NOT NULL CHECK(retry_count>=0), next_retry_at TEXT, suppression_reason TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,delivery_id), UNIQUE(user_scope_id,logical_change_id,target_peer_identity_id), FOREIGN KEY(user_scope_id,logical_change_id) REFERENCES logical_sync_changes(user_scope_id,logical_change_id), FOREIGN KEY(user_scope_id,target_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,relayed_from_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,batch_id) REFERENCES sync_batches(user_scope_id,batch_id),
      CHECK((delivery_state='in_batch')=(batch_id IS NOT NULL)), CHECK((delivery_state='acked')=(ack_id IS NOT NULL AND acked_sequence IS NOT NULL AND acked_chain_digest IS NOT NULL)), CHECK((delivery_state='retryable')=(next_retry_at IS NOT NULL)), CHECK((delivery_state='suppressed')=(suppression_reason IS NOT NULL))
    ) STRICT;

    CREATE TABLE received_changes (
      user_scope_id TEXT NOT NULL, receipt_id TEXT NOT NULL CHECK(length(receipt_id)=36), source_peer_identity_id TEXT NOT NULL, batch_id TEXT NOT NULL, logical_change_id TEXT NOT NULL,
      origin_device_identity_id TEXT NOT NULL, origin_change_id TEXT NOT NULL, stream_kind TEXT NOT NULL, change_sequence INTEGER NOT NULL CHECK(change_sequence>=0), previous_chain_digest BLOB, chain_digest BLOB NOT NULL CHECK(length(chain_digest)=32), entity_kind TEXT NOT NULL, entity_id TEXT NOT NULL, entity_schema_version INTEGER NOT NULL CHECK(entity_schema_version>=1), content_digest BLOB NOT NULL CHECK(length(content_digest)=32), relay_hop_count INTEGER NOT NULL CHECK(relay_hop_count>=0),
      apply_state TEXT NOT NULL CHECK(apply_state IN ('validated','applied','duplicate','conflicted','quarantined')), applied_revision INTEGER, conflict_id TEXT, quarantine_id TEXT, applied_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,receipt_id), UNIQUE(user_scope_id,source_peer_identity_id,origin_device_identity_id,origin_change_id), UNIQUE(user_scope_id,source_peer_identity_id,origin_device_identity_id,stream_kind,change_sequence),
      FOREIGN KEY(user_scope_id,source_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,batch_id) REFERENCES sync_batches(user_scope_id,batch_id), FOREIGN KEY(user_scope_id,logical_change_id) REFERENCES logical_sync_changes(user_scope_id,logical_change_id), FOREIGN KEY(user_scope_id,conflict_id) REFERENCES sync_conflicts(user_scope_id,conflict_id), FOREIGN KEY(user_scope_id,quarantine_id) REFERENCES sync_quarantine_items(user_scope_id,quarantine_id),
      CHECK((change_sequence=0 AND previous_chain_digest IS NULL) OR change_sequence>0),
      CHECK((apply_state IN ('applied','duplicate') AND applied_revision IS NOT NULL AND applied_at IS NOT NULL AND conflict_id IS NULL AND quarantine_id IS NULL) OR (apply_state='conflicted' AND conflict_id IS NOT NULL AND applied_revision IS NULL AND applied_at IS NULL AND quarantine_id IS NULL) OR (apply_state='quarantined' AND quarantine_id IS NOT NULL AND applied_revision IS NULL AND applied_at IS NULL AND conflict_id IS NULL) OR (apply_state='validated' AND applied_revision IS NULL AND applied_at IS NULL AND conflict_id IS NULL AND quarantine_id IS NULL))
    ) STRICT;

    CREATE TABLE peer_sync_cursors (
      user_scope_id TEXT NOT NULL, peer_identity_id TEXT NOT NULL, direction TEXT NOT NULL CHECK(direction IN ('sent','received')), origin_device_identity_id TEXT NOT NULL, stream_kind TEXT NOT NULL CHECK(stream_kind IN ('vehicle_display_name','vehicle_lifecycle','immutable_identity','session_log')),
      next_expected_sequence INTEGER NOT NULL CHECK(next_expected_sequence>=0), last_change_id TEXT, last_chain_digest BLOB,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,peer_identity_id,direction,origin_device_identity_id,stream_kind), FOREIGN KEY(user_scope_id,peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id),
      CHECK((next_expected_sequence=0 AND last_change_id IS NULL AND last_chain_digest IS NULL) OR (next_expected_sequence>0 AND last_change_id IS NOT NULL AND length(last_chain_digest)=32))
    ) STRICT;

    CREATE TABLE session_transfers (
      user_scope_id TEXT NOT NULL, session_transfer_id TEXT NOT NULL CHECK(length(session_transfer_id)=36), batch_id TEXT NOT NULL, session_id TEXT NOT NULL CHECK(length(session_id)=36), manifest_digest BLOB NOT NULL CHECK(length(manifest_digest)=32), expected_chunk_count INTEGER NOT NULL CHECK(expected_chunk_count>=0), expected_ciphertext_bytes INTEGER NOT NULL CHECK(expected_ciphertext_bytes>=0),
      transfer_state TEXT NOT NULL CHECK(transfer_state IN ('manifest_pending','transferring','verifying','durable','acknowledged','retryable','blocked')), durable_ack_id TEXT, durable_ack_binding_digest BLOB, durable_at TEXT, acknowledged_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,session_transfer_id), UNIQUE(user_scope_id,batch_id,session_id), FOREIGN KEY(user_scope_id,batch_id) REFERENCES sync_batches(user_scope_id,batch_id),
      CHECK((transfer_state IN ('durable','acknowledged'))=(durable_ack_id IS NOT NULL AND length(durable_ack_binding_digest)=32 AND durable_at IS NOT NULL)), CHECK((transfer_state='acknowledged')=(acknowledged_at IS NOT NULL))
    ) STRICT;

    CREATE TABLE chunk_transfers (
      user_scope_id TEXT NOT NULL, chunk_transfer_id TEXT NOT NULL CHECK(length(chunk_transfer_id)=36), session_transfer_id TEXT NOT NULL, session_id TEXT NOT NULL CHECK(length(session_id)=36), chunk_id TEXT NOT NULL CHECK(length(chunk_id)=36), stream_id TEXT NOT NULL CHECK(length(stream_id)=36), chunk_sequence INTEGER NOT NULL CHECK(chunk_sequence>=0), clock_epoch_id TEXT NOT NULL CHECK(length(clock_epoch_id)=36), first_record_sequence INTEGER NOT NULL CHECK(first_record_sequence>=0), last_record_sequence INTEGER NOT NULL CHECK(last_record_sequence>=first_record_sequence), first_monotonic_ns INTEGER NOT NULL CHECK(first_monotonic_ns>=0), last_monotonic_ns INTEGER NOT NULL CHECK(last_monotonic_ns>=first_monotonic_ns), record_count INTEGER NOT NULL CHECK(record_count>0), plaintext_size INTEGER NOT NULL CHECK(plaintext_size>=0), compressed_size INTEGER NOT NULL CHECK(compressed_size>=0), ciphertext_size INTEGER NOT NULL CHECK(ciphertext_size>0), ciphertext_digest BLOB NOT NULL CHECK(length(ciphertext_digest)=32), catalog_digest BLOB NOT NULL CHECK(length(catalog_digest)=32),
      record_format_version INTEGER NOT NULL CHECK(record_format_version>=1), compression_format_version INTEGER NOT NULL CHECK(compression_format_version>=1), encryption_format_version INTEGER NOT NULL CHECK(encryption_format_version>=1), key_version INTEGER NOT NULL CHECK(key_version>=1),
      catalog_relative_path TEXT NOT NULL, catalog_storage_state TEXT NOT NULL CHECK(catalog_storage_state='available'), catalog_revision INTEGER NOT NULL CHECK(catalog_revision>=1), catalog_created_at_utc TEXT NOT NULL, catalog_updated_at_utc TEXT NOT NULL,
      transfer_state TEXT NOT NULL CHECK(transfer_state IN ('pending','receiving','segments_complete','verified','file_durable','cataloged','quarantined')), staging_relative_path TEXT, cataloged_at TEXT, quarantine_id TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,chunk_transfer_id), UNIQUE(user_scope_id,session_transfer_id,chunk_id), UNIQUE(user_scope_id,session_transfer_id,stream_id,chunk_sequence), FOREIGN KEY(user_scope_id,session_transfer_id) REFERENCES session_transfers(user_scope_id,session_transfer_id), FOREIGN KEY(user_scope_id,quarantine_id) REFERENCES sync_quarantine_items(user_scope_id,quarantine_id),
      CHECK(record_count=last_record_sequence-first_record_sequence+1),
      CHECK((transfer_state IN ('receiving','segments_complete','verified','file_durable') AND staging_relative_path IS NOT NULL AND cataloged_at IS NULL AND quarantine_id IS NULL) OR (transfer_state='cataloged' AND staging_relative_path IS NULL AND cataloged_at IS NOT NULL AND quarantine_id IS NULL) OR (transfer_state='quarantined' AND quarantine_id IS NOT NULL AND cataloged_at IS NULL) OR (transfer_state='pending' AND staging_relative_path IS NULL AND cataloged_at IS NULL AND quarantine_id IS NULL))
    ) STRICT;

    CREATE TABLE chunk_transfer_segments (
      user_scope_id TEXT NOT NULL, chunk_transfer_id TEXT NOT NULL, segment_index INTEGER NOT NULL CHECK(segment_index>=0), byte_offset INTEGER NOT NULL CHECK(byte_offset>=0), byte_length INTEGER NOT NULL CHECK(byte_length>0), segment_digest BLOB NOT NULL CHECK(length(segment_digest)=32),
      segment_state TEXT NOT NULL CHECK(segment_state IN ('expected','received','verified')), received_at TEXT, verified_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,chunk_transfer_id,segment_index), UNIQUE(user_scope_id,chunk_transfer_id,byte_offset), FOREIGN KEY(user_scope_id,chunk_transfer_id) REFERENCES chunk_transfers(user_scope_id,chunk_transfer_id),
      CHECK((segment_state='expected' AND received_at IS NULL AND verified_at IS NULL) OR (segment_state='received' AND received_at IS NOT NULL AND verified_at IS NULL) OR (segment_state='verified' AND received_at IS NOT NULL AND verified_at IS NOT NULL))
    ) STRICT;

    CREATE TABLE vehicle_id_aliases (
      user_scope_id TEXT NOT NULL, vehicle_alias_id TEXT NOT NULL CHECK(length(vehicle_alias_id)=36), source_peer_identity_id TEXT NOT NULL, source_vehicle_id TEXT NOT NULL CHECK(length(source_vehicle_id)=36), canonical_vehicle_id TEXT NOT NULL CHECK(length(canonical_vehicle_id)=36), alias_revision INTEGER NOT NULL CHECK(alias_revision>=1), previous_alias_id TEXT,
      match_basis_kind TEXT NOT NULL CHECK(match_basis_kind IN ('same_entity_id','single_valid_identifier_digest','user_confirmed')), basis_digest BLOB, graph_source_frontier BLOB NOT NULL CHECK(length(graph_source_frontier)>0), graph_manifest_digest BLOB NOT NULL CHECK(length(graph_manifest_digest)=32), expected_materialization_count INTEGER NOT NULL CHECK(expected_materialization_count>=0),
      mapping_state TEXT NOT NULL CHECK(mapping_state IN ('preparing','ready','active','superseded','conflicted')), ready_at TEXT, activated_at TEXT, superseded_by_alias_id TEXT, superseded_at TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,vehicle_alias_id), UNIQUE(user_scope_id,vehicle_alias_id,alias_revision), UNIQUE(user_scope_id,source_peer_identity_id,source_vehicle_id,alias_revision),
      FOREIGN KEY(user_scope_id,source_peer_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,canonical_vehicle_id) REFERENCES vehicles(user_scope_id,vehicle_id), FOREIGN KEY(user_scope_id,previous_alias_id) REFERENCES vehicle_id_aliases(user_scope_id,vehicle_alias_id) DEFERRABLE INITIALLY DEFERRED, FOREIGN KEY(user_scope_id,superseded_by_alias_id) REFERENCES vehicle_id_aliases(user_scope_id,vehicle_alias_id) DEFERRABLE INITIALLY DEFERRED,
      CHECK((alias_revision=1 AND previous_alias_id IS NULL) OR (alias_revision>1 AND previous_alias_id IS NOT NULL)), CHECK(previous_alias_id IS NULL OR previous_alias_id<>vehicle_alias_id), CHECK(superseded_by_alias_id IS NULL OR superseded_by_alias_id<>vehicle_alias_id),
      CHECK((match_basis_kind='same_entity_id' AND basis_digest IS NULL) OR (match_basis_kind='single_valid_identifier_digest' AND length(basis_digest)=32) OR (match_basis_kind='user_confirmed' AND (basis_digest IS NULL OR length(basis_digest)=32))),
      CHECK((mapping_state='preparing' AND ready_at IS NULL AND activated_at IS NULL AND superseded_by_alias_id IS NULL AND superseded_at IS NULL) OR (mapping_state='ready' AND ready_at IS NOT NULL AND activated_at IS NULL AND superseded_by_alias_id IS NULL AND superseded_at IS NULL) OR (mapping_state='active' AND ready_at IS NOT NULL AND activated_at IS NOT NULL AND superseded_by_alias_id IS NULL AND superseded_at IS NULL) OR (mapping_state='superseded' AND ready_at IS NOT NULL AND activated_at IS NOT NULL AND superseded_by_alias_id IS NOT NULL AND superseded_at IS NOT NULL) OR (mapping_state='conflicted' AND activated_at IS NULL AND superseded_at IS NULL AND superseded_by_alias_id IS NULL))
    ) STRICT;
    CREATE UNIQUE INDEX one_active_alias_graph ON vehicle_id_aliases(user_scope_id,source_peer_identity_id,source_vehicle_id) WHERE mapping_state='active';

    CREATE TABLE origin_entity_materializations (
      user_scope_id TEXT NOT NULL, materialization_id TEXT NOT NULL CHECK(length(materialization_id)=36), logical_change_id TEXT NOT NULL, origin_device_identity_id TEXT NOT NULL, origin_change_id TEXT NOT NULL, entity_kind TEXT NOT NULL, origin_entity_id TEXT NOT NULL, origin_vehicle_id TEXT NOT NULL,
      origin_parent_entity_kind TEXT NOT NULL, origin_parent_entity_id TEXT NOT NULL, origin_entity_version INTEGER NOT NULL CHECK(origin_entity_version>=1), origin_content_digest BLOB NOT NULL CHECK(length(origin_content_digest)=32), origin_envelope_storage TEXT NOT NULL CHECK(origin_envelope_storage='logical_change_ciphertext'),
      vehicle_alias_id TEXT NOT NULL, graph_generation INTEGER NOT NULL CHECK(graph_generation>=1), projection_version INTEGER NOT NULL CHECK(projection_version>=1), canonical_vehicle_id TEXT NOT NULL,
      parent_materialization_id TEXT, materialized_parent_entity_id TEXT NOT NULL, origin_secondary_parent_entity_kind TEXT, origin_secondary_parent_entity_id TEXT, secondary_parent_materialization_id TEXT, materialized_secondary_parent_entity_id TEXT, origin_tertiary_parent_entity_kind TEXT, origin_tertiary_parent_entity_id TEXT, tertiary_parent_materialization_id TEXT, materialized_tertiary_parent_entity_id TEXT,
      materialization_result_kind TEXT NOT NULL CHECK(materialization_result_kind IN ('inserted_projection','linked_existing_duplicate')), materialized_identifier_kind TEXT, materialized_identifier_digest_key_version INTEGER, materialized_identifier_lookup_digest BLOB,
      materialized_content_digest BLOB NOT NULL CHECK(length(materialized_content_digest)=32), materialized_entity_id TEXT NOT NULL CHECK(length(materialized_entity_id)=36), materialization_state TEXT NOT NULL CHECK(materialization_state IN ('projected','applied','conflicted','quarantined','superseded_projection')), relay_eligibility TEXT NOT NULL CHECK(relay_eligibility IN ('metadata_relay_allowed','origin_only_no_relay')),
      received_at TEXT NOT NULL, applied_at TEXT, superseded_by_materialization_id TEXT, superseded_at TEXT, created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,materialization_id), UNIQUE(user_scope_id,logical_change_id,vehicle_alias_id,graph_generation,projection_version),
      FOREIGN KEY(user_scope_id,logical_change_id) REFERENCES logical_sync_changes(user_scope_id,logical_change_id), FOREIGN KEY(user_scope_id,vehicle_alias_id,graph_generation) REFERENCES vehicle_id_aliases(user_scope_id,vehicle_alias_id,alias_revision), FOREIGN KEY(user_scope_id,canonical_vehicle_id) REFERENCES vehicles(user_scope_id,vehicle_id),
      FOREIGN KEY(user_scope_id,parent_materialization_id) REFERENCES origin_entity_materializations(user_scope_id,materialization_id) DEFERRABLE INITIALLY DEFERRED, FOREIGN KEY(user_scope_id,secondary_parent_materialization_id) REFERENCES origin_entity_materializations(user_scope_id,materialization_id) DEFERRABLE INITIALLY DEFERRED, FOREIGN KEY(user_scope_id,tertiary_parent_materialization_id) REFERENCES origin_entity_materializations(user_scope_id,materialization_id) DEFERRABLE INITIALLY DEFERRED,
      CHECK((origin_secondary_parent_entity_kind IS NULL AND origin_secondary_parent_entity_id IS NULL AND secondary_parent_materialization_id IS NULL AND materialized_secondary_parent_entity_id IS NULL) OR (origin_secondary_parent_entity_kind IS NOT NULL AND origin_secondary_parent_entity_id IS NOT NULL AND secondary_parent_materialization_id IS NOT NULL AND materialized_secondary_parent_entity_id IS NOT NULL)),
      CHECK((origin_tertiary_parent_entity_kind IS NULL AND origin_tertiary_parent_entity_id IS NULL AND tertiary_parent_materialization_id IS NULL AND materialized_tertiary_parent_entity_id IS NULL) OR (origin_tertiary_parent_entity_kind IS NOT NULL AND origin_tertiary_parent_entity_id IS NOT NULL AND tertiary_parent_materialization_id IS NOT NULL AND materialized_tertiary_parent_entity_id IS NOT NULL)),
      CHECK((entity_kind='vehicle_identifier' AND materialized_identifier_kind IN ('vin','domestic_chassis_number') AND materialized_identifier_digest_key_version>=1 AND length(materialized_identifier_lookup_digest)=32) OR (entity_kind<>'vehicle_identifier' AND materialized_identifier_kind IS NULL AND materialized_identifier_digest_key_version IS NULL AND materialized_identifier_lookup_digest IS NULL)),
      CHECK(materialization_result_kind='inserted_projection' OR entity_kind='vehicle_identifier'),
      CHECK((materialization_state='applied' AND applied_at IS NOT NULL AND superseded_by_materialization_id IS NULL AND superseded_at IS NULL) OR (materialization_state='superseded_projection' AND applied_at IS NOT NULL AND superseded_by_materialization_id IS NOT NULL AND superseded_at IS NOT NULL) OR (materialization_state IN ('projected','conflicted','quarantined') AND applied_at IS NULL AND superseded_by_materialization_id IS NULL AND superseded_at IS NULL))
    ) STRICT;

    CREATE TABLE sync_conflict_candidates (
      user_scope_id TEXT NOT NULL, conflict_id TEXT NOT NULL, candidate_id TEXT NOT NULL CHECK(length(candidate_id)=36), origin_kind TEXT NOT NULL CHECK(origin_kind IN ('local','peer','resolution')), origin_device_id TEXT NOT NULL, candidate_revision INTEGER NOT NULL CHECK(candidate_revision>=0), content_digest BLOB NOT NULL CHECK(length(content_digest)=32), candidate_ciphertext BLOB NOT NULL, is_selected INTEGER NOT NULL CHECK(is_selected IN (0,1)), created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL,
      PRIMARY KEY(user_scope_id,conflict_id,candidate_id), UNIQUE(user_scope_id,conflict_id,origin_kind,candidate_revision,content_digest), FOREIGN KEY(user_scope_id,conflict_id) REFERENCES sync_conflicts(user_scope_id,conflict_id)
    ) STRICT;
    CREATE UNIQUE INDEX one_selected_conflict_candidate ON sync_conflict_candidates(user_scope_id,conflict_id) WHERE is_selected=1;

    CREATE TABLE wrapped_key_receipts (
      user_scope_id TEXT NOT NULL, key_envelope_id TEXT NOT NULL CHECK(length(key_envelope_id)=36), sender_identity_id TEXT NOT NULL, sender_signing_key_version INTEGER NOT NULL CHECK(sender_signing_key_version>=1), recipient_identity_id TEXT NOT NULL, recipient_agreement_key_version INTEGER NOT NULL CHECK(recipient_agreement_key_version>=1), trust_generation INTEGER NOT NULL CHECK(trust_generation>=1),
      key_purpose TEXT NOT NULL CHECK(key_purpose IN ('membership','vehicle_encryption','vehicle_digest','session_chunk')), wrapped_key_version INTEGER NOT NULL CHECK(wrapped_key_version>=1), bound_session_id TEXT, bound_chunk_id TEXT, nonce_digest BLOB NOT NULL CHECK(length(nonce_digest)=32), envelope_digest BLOB NOT NULL CHECK(length(envelope_digest)=32), envelope_ciphertext BLOB NOT NULL,
      receipt_state TEXT NOT NULL CHECK(receipt_state IN ('received','verified','applied','quarantined')), applied_keychain_reference_id TEXT, applied_at TEXT, quarantine_id TEXT,
      created_at TEXT NOT NULL, created_by_device_id TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by_device_id TEXT NOT NULL, revision INTEGER NOT NULL CHECK(revision>=1),
      PRIMARY KEY(user_scope_id,key_envelope_id), UNIQUE(user_scope_id,sender_identity_id,nonce_digest), FOREIGN KEY(user_scope_id,sender_identity_id) REFERENCES paired_devices(user_scope_id,peer_identity_id), FOREIGN KEY(user_scope_id,quarantine_id) REFERENCES sync_quarantine_items(user_scope_id,quarantine_id),
      CHECK((key_purpose='session_chunk' AND length(bound_session_id)=36 AND length(bound_chunk_id)=36) OR (key_purpose<>'session_chunk' AND bound_session_id IS NULL AND bound_chunk_id IS NULL)),
      CHECK((receipt_state='applied' AND applied_keychain_reference_id IS NOT NULL AND applied_at IS NOT NULL AND quarantine_id IS NULL) OR (receipt_state='quarantined' AND quarantine_id IS NOT NULL AND applied_keychain_reference_id IS NULL AND applied_at IS NULL) OR (receipt_state IN ('received','verified') AND applied_keychain_reference_id IS NULL AND applied_at IS NULL AND quarantine_id IS NULL))
    ) STRICT;

    CREATE TRIGGER local_identity_scope_insert BEFORE INSERT ON local_device_identity WHEN NEW.user_scope_id<>(SELECT user_scope_id FROM database_scope WHERE scope_row_id=1) BEGIN SELECT RAISE(ABORT,'scope mismatch'); END;
    CREATE TRIGGER local_identity_no_delete BEFORE DELETE ON local_device_identity BEGIN SELECT RAISE(ABORT,'local identity cannot be deleted'); END;
    CREATE TRIGGER paired_gate_insert BEFORE INSERT ON paired_devices WHEN NEW.pairing_state='paired' AND (NEW.membership_verification_state<>'verified' OR NOT EXISTS(SELECT 1 FROM local_device_identity l WHERE l.user_scope_id=NEW.user_scope_id AND l.membership_state='established')) BEGIN SELECT RAISE(ABORT,'membership hard gate'); END;
    CREATE TRIGGER paired_gate_update BEFORE UPDATE OF pairing_state ON paired_devices WHEN NEW.pairing_state='paired' AND (NEW.membership_verification_state<>'verified' OR NOT EXISTS(SELECT 1 FROM local_device_identity l WHERE l.user_scope_id=NEW.user_scope_id AND l.membership_state='established')) BEGIN SELECT RAISE(ABORT,'membership hard gate'); END;

    CREATE TRIGGER logical_change_chain_insert BEFORE INSERT ON logical_sync_changes BEGIN
      SELECT CASE WHEN NEW.user_scope_id<>(SELECT user_scope_id FROM database_scope WHERE scope_row_id=1) THEN RAISE(ABORT,'scope mismatch') END;
      SELECT CASE WHEN NEW.change_sequence>0 AND NOT EXISTS(SELECT 1 FROM logical_sync_changes p WHERE p.user_scope_id=NEW.user_scope_id AND p.origin_device_identity_id=NEW.origin_device_identity_id AND p.stream_kind=NEW.stream_kind AND p.change_sequence=NEW.change_sequence-1 AND p.origin_change_id=NEW.previous_change_id AND p.chain_digest=NEW.previous_chain_digest) THEN RAISE(ABORT,'missing chain predecessor') END;
      SELECT CASE WHEN NEW.chain_digest<>sync_chain_digest_v1(NEW.origin_device_identity_id,NEW.origin_signing_key_version,NEW.origin_signing_key_fingerprint,NEW.stream_kind,NEW.change_sequence,NEW.origin_change_id,NEW.entity_kind,NEW.entity_id,NEW.origin_vehicle_id,NEW.origin_parent_entity_kind,NEW.origin_parent_entity_id,NEW.origin_secondary_parent_entity_kind,NEW.origin_secondary_parent_entity_id,NEW.origin_tertiary_parent_entity_kind,NEW.origin_tertiary_parent_entity_id,NEW.entity_schema_version,NEW.content_digest,NEW.previous_chain_digest) THEN RAISE(ABORT,'chain digest mismatch') END;
    END;
    CREATE TRIGGER logical_change_no_update BEFORE UPDATE ON logical_sync_changes BEGIN SELECT RAISE(ABORT,'logical changes are immutable'); END;
    CREATE TRIGGER logical_change_no_delete BEFORE DELETE ON logical_sync_changes BEGIN SELECT RAISE(ABORT,'logical changes cannot be deleted'); END;

    CREATE TRIGGER delivery_no_reflection BEFORE INSERT ON sync_change_deliveries WHEN EXISTS(SELECT 1 FROM received_changes r WHERE r.user_scope_id=NEW.user_scope_id AND r.logical_change_id=NEW.logical_change_id AND r.source_peer_identity_id=NEW.target_peer_identity_id) BEGIN SELECT RAISE(ABORT,'relay reflection'); END;
    CREATE TRIGGER delivery_requires_trust BEFORE INSERT ON sync_change_deliveries WHEN NOT EXISTS(SELECT 1 FROM paired_devices p JOIN device_trust_records t USING(user_scope_id,peer_identity_id) WHERE p.user_scope_id=NEW.user_scope_id AND p.peer_identity_id=NEW.target_peer_identity_id AND p.membership_verification_state='verified' AND p.pairing_state='paired' AND t.trust_state='trusted') BEGIN SELECT RAISE(ABORT,'untrusted delivery target'); END;
    CREATE TRIGGER delivery_ack_matches BEFORE UPDATE OF delivery_state ON sync_change_deliveries WHEN NEW.delivery_state='acked' AND NOT EXISTS(SELECT 1 FROM logical_sync_changes c WHERE c.user_scope_id=NEW.user_scope_id AND c.logical_change_id=NEW.logical_change_id AND c.change_sequence=NEW.acked_sequence AND c.chain_digest=NEW.acked_chain_digest) BEGIN SELECT RAISE(ABORT,'ack mismatch'); END;

    CREATE TRIGGER receipt_matches_change BEFORE INSERT ON received_changes WHEN NOT EXISTS(SELECT 1 FROM logical_sync_changes c WHERE c.user_scope_id=NEW.user_scope_id AND c.logical_change_id=NEW.logical_change_id AND c.origin_device_identity_id=NEW.origin_device_identity_id AND c.origin_change_id=NEW.origin_change_id AND c.stream_kind=NEW.stream_kind AND c.change_sequence=NEW.change_sequence AND c.previous_chain_digest IS NEW.previous_chain_digest AND c.chain_digest=NEW.chain_digest AND c.entity_kind=NEW.entity_kind AND c.entity_id=NEW.entity_id AND c.entity_schema_version=NEW.entity_schema_version AND c.content_digest=NEW.content_digest) BEGIN SELECT RAISE(ABORT,'receipt envelope mismatch'); END;
    CREATE TRIGGER receipt_transition_guard BEFORE UPDATE OF apply_state ON received_changes WHEN OLD.apply_state<>'validated' OR NEW.apply_state NOT IN ('applied','duplicate','conflicted','quarantined') BEGIN SELECT RAISE(ABORT,'invalid receipt transition'); END;

    CREATE TRIGGER cursor_single_step BEFORE UPDATE ON peer_sync_cursors BEGIN
      SELECT CASE WHEN NEW.next_expected_sequence<>OLD.next_expected_sequence+1 OR NEW.revision<>OLD.revision+1 THEN RAISE(ABORT,'cursor must advance exactly one') END;
      SELECT CASE WHEN NOT EXISTS(SELECT 1 FROM logical_sync_changes c WHERE c.user_scope_id=OLD.user_scope_id AND c.origin_device_identity_id=OLD.origin_device_identity_id AND c.stream_kind=OLD.stream_kind AND c.change_sequence=OLD.next_expected_sequence AND c.previous_chain_digest IS OLD.last_chain_digest AND c.origin_change_id=NEW.last_change_id AND c.chain_digest=NEW.last_chain_digest) THEN RAISE(ABORT,'cursor chain gap') END;
      SELECT CASE WHEN OLD.direction='received' AND NOT EXISTS(SELECT 1 FROM received_changes r WHERE r.user_scope_id=OLD.user_scope_id AND r.source_peer_identity_id=OLD.peer_identity_id AND r.origin_device_identity_id=OLD.origin_device_identity_id AND r.stream_kind=OLD.stream_kind AND r.change_sequence=OLD.next_expected_sequence AND r.apply_state IN ('applied','duplicate')) THEN RAISE(ABORT,'receipt not applied') END;
      SELECT CASE WHEN OLD.direction='sent' AND NOT EXISTS(SELECT 1 FROM sync_change_deliveries d JOIN logical_sync_changes c ON c.user_scope_id=d.user_scope_id AND c.logical_change_id=d.logical_change_id WHERE d.user_scope_id=OLD.user_scope_id AND d.target_peer_identity_id=OLD.peer_identity_id AND c.origin_device_identity_id=OLD.origin_device_identity_id AND c.stream_kind=OLD.stream_kind AND c.change_sequence=OLD.next_expected_sequence AND d.delivery_state='acked') THEN RAISE(ABORT,'delivery not acked') END;
    END;

    CREATE TRIGGER alias_revision_insert BEFORE INSERT ON vehicle_id_aliases WHEN NEW.alias_revision>1 AND NOT EXISTS(SELECT 1 FROM vehicle_id_aliases p WHERE p.user_scope_id=NEW.user_scope_id AND p.vehicle_alias_id=NEW.previous_alias_id AND p.source_peer_identity_id=NEW.source_peer_identity_id AND p.source_vehicle_id=NEW.source_vehicle_id AND p.alias_revision=NEW.alias_revision-1) BEGIN SELECT RAISE(ABORT,'invalid alias predecessor'); END;
    CREATE TRIGGER alias_ready_guard BEFORE UPDATE OF mapping_state ON vehicle_id_aliases WHEN NEW.mapping_state='ready' AND (OLD.mapping_state<>'preparing' OR (SELECT COUNT(*) FROM origin_entity_materializations m WHERE m.user_scope_id=NEW.user_scope_id AND m.vehicle_alias_id=NEW.vehicle_alias_id AND m.graph_generation=NEW.alias_revision AND m.materialization_state='applied')<>NEW.expected_materialization_count) BEGIN SELECT RAISE(ABORT,'alias graph not ready'); END;
    CREATE TRIGGER alias_transition_guard BEFORE UPDATE OF mapping_state ON vehicle_id_aliases WHEN NOT((OLD.mapping_state='preparing' AND NEW.mapping_state IN ('ready','conflicted')) OR (OLD.mapping_state='ready' AND NEW.mapping_state IN ('active','conflicted')) OR (OLD.mapping_state='active' AND NEW.mapping_state='superseded')) BEGIN SELECT RAISE(ABORT,'invalid alias transition'); END;
    CREATE TRIGGER alias_immutable_columns BEFORE UPDATE ON vehicle_id_aliases WHEN NEW.user_scope_id<>OLD.user_scope_id OR NEW.vehicle_alias_id<>OLD.vehicle_alias_id OR NEW.source_peer_identity_id<>OLD.source_peer_identity_id OR NEW.source_vehicle_id<>OLD.source_vehicle_id OR NEW.canonical_vehicle_id<>OLD.canonical_vehicle_id OR NEW.alias_revision<>OLD.alias_revision OR NEW.previous_alias_id IS NOT OLD.previous_alias_id OR NEW.graph_source_frontier<>OLD.graph_source_frontier OR (NEW.graph_manifest_digest<>OLD.graph_manifest_digest AND (OLD.mapping_state<>'preparing' OR NEW.mapping_state<>'preparing' OR EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=OLD.user_scope_id AND m.vehicle_alias_id=OLD.vehicle_alias_id AND m.graph_generation=OLD.alias_revision AND m.materialization_state<>'projected'))) OR NEW.expected_materialization_count<>OLD.expected_materialization_count BEGIN SELECT RAISE(ABORT,'immutable alias columns'); END;

    CREATE TRIGGER materialization_insert_guard BEFORE INSERT ON origin_entity_materializations BEGIN
      SELECT CASE WHEN NOT EXISTS(SELECT 1 FROM logical_sync_changes c WHERE c.user_scope_id=NEW.user_scope_id AND c.logical_change_id=NEW.logical_change_id AND c.origin_device_identity_id=NEW.origin_device_identity_id AND c.origin_change_id=NEW.origin_change_id AND c.entity_kind=NEW.entity_kind AND c.entity_id=NEW.origin_entity_id AND c.origin_vehicle_id=NEW.origin_vehicle_id AND c.origin_parent_entity_kind=NEW.origin_parent_entity_kind AND c.origin_parent_entity_id=NEW.origin_parent_entity_id AND c.origin_secondary_parent_entity_kind IS NEW.origin_secondary_parent_entity_kind AND c.origin_secondary_parent_entity_id IS NEW.origin_secondary_parent_entity_id AND c.origin_tertiary_parent_entity_kind IS NEW.origin_tertiary_parent_entity_kind AND c.origin_tertiary_parent_entity_id IS NEW.origin_tertiary_parent_entity_id AND c.entity_schema_version=NEW.origin_entity_version AND c.content_digest=NEW.origin_content_digest) THEN RAISE(ABORT,'origin envelope mismatch') END;
      SELECT CASE WHEN NOT EXISTS(SELECT 1 FROM vehicle_id_aliases a WHERE a.user_scope_id=NEW.user_scope_id AND a.vehicle_alias_id=NEW.vehicle_alias_id AND a.alias_revision=NEW.graph_generation AND a.source_vehicle_id=NEW.origin_vehicle_id AND a.canonical_vehicle_id=NEW.canonical_vehicle_id AND a.mapping_state IN ('preparing','active')) THEN RAISE(ABORT,'alias graph mismatch') END;
      SELECT CASE WHEN NEW.materialization_result_kind='inserted_projection' AND EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=NEW.user_scope_id AND m.entity_kind=NEW.entity_kind AND m.materialized_entity_id=NEW.materialized_entity_id AND m.materialization_result_kind='inserted_projection') THEN RAISE(ABORT,'projection ownership conflict') END;
      SELECT CASE WHEN NEW.parent_materialization_id IS NULL AND NOT(NEW.origin_parent_entity_kind='vehicle' AND NEW.origin_parent_entity_id=(SELECT source_vehicle_id FROM vehicle_id_aliases WHERE user_scope_id=NEW.user_scope_id AND vehicle_alias_id=NEW.vehicle_alias_id AND alias_revision=NEW.graph_generation) AND NEW.materialized_parent_entity_id=NEW.canonical_vehicle_id) THEN RAISE(ABORT,'unbound direct parent') END;
      SELECT CASE WHEN NEW.parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=NEW.user_scope_id AND p.materialization_id=NEW.parent_materialization_id AND p.entity_kind=NEW.origin_parent_entity_kind AND p.origin_entity_id=NEW.origin_parent_entity_id AND p.materialized_entity_id=NEW.materialized_parent_entity_id AND p.vehicle_alias_id=NEW.vehicle_alias_id AND p.graph_generation=NEW.graph_generation AND p.canonical_vehicle_id=NEW.canonical_vehicle_id AND p.origin_device_identity_id=NEW.origin_device_identity_id AND p.origin_vehicle_id=NEW.origin_vehicle_id) THEN RAISE(ABORT,'direct parent semantic mismatch') END;
      SELECT CASE WHEN NEW.secondary_parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=NEW.user_scope_id AND p.materialization_id=NEW.secondary_parent_materialization_id AND p.entity_kind=NEW.origin_secondary_parent_entity_kind AND p.origin_entity_id=NEW.origin_secondary_parent_entity_id AND p.materialized_entity_id=NEW.materialized_secondary_parent_entity_id AND p.vehicle_alias_id=NEW.vehicle_alias_id AND p.graph_generation=NEW.graph_generation AND p.canonical_vehicle_id=NEW.canonical_vehicle_id AND p.origin_device_identity_id=NEW.origin_device_identity_id AND p.origin_vehicle_id=NEW.origin_vehicle_id) THEN RAISE(ABORT,'secondary parent semantic mismatch') END;
      SELECT CASE WHEN NEW.tertiary_parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=NEW.user_scope_id AND p.materialization_id=NEW.tertiary_parent_materialization_id AND p.entity_kind=NEW.origin_tertiary_parent_entity_kind AND p.origin_entity_id=NEW.origin_tertiary_parent_entity_id AND p.materialized_entity_id=NEW.materialized_tertiary_parent_entity_id AND p.vehicle_alias_id=NEW.vehicle_alias_id AND p.graph_generation=NEW.graph_generation AND p.canonical_vehicle_id=NEW.canonical_vehicle_id AND p.origin_device_identity_id=NEW.origin_device_identity_id AND p.origin_vehicle_id=NEW.origin_vehicle_id) THEN RAISE(ABORT,'tertiary parent semantic mismatch') END;
    END;
    CREATE TRIGGER materialization_apply_guard BEFORE UPDATE OF materialization_state ON origin_entity_materializations WHEN NEW.materialization_state='applied' BEGIN
      SELECT CASE WHEN OLD.materialization_state<>'projected' THEN RAISE(ABORT,'invalid materialization transition') END;
      SELECT CASE WHEN NOT EXISTS(SELECT 1 FROM logical_sync_changes c WHERE c.user_scope_id=OLD.user_scope_id AND c.logical_change_id=OLD.logical_change_id AND c.origin_device_identity_id=OLD.origin_device_identity_id AND c.origin_change_id=OLD.origin_change_id AND c.entity_kind=OLD.entity_kind AND c.entity_id=OLD.origin_entity_id AND c.origin_vehicle_id=OLD.origin_vehicle_id AND c.origin_parent_entity_kind=OLD.origin_parent_entity_kind AND c.origin_parent_entity_id=OLD.origin_parent_entity_id AND c.origin_secondary_parent_entity_kind IS OLD.origin_secondary_parent_entity_kind AND c.origin_secondary_parent_entity_id IS OLD.origin_secondary_parent_entity_id AND c.origin_tertiary_parent_entity_kind IS OLD.origin_tertiary_parent_entity_kind AND c.origin_tertiary_parent_entity_id IS OLD.origin_tertiary_parent_entity_id AND c.entity_schema_version=OLD.origin_entity_version AND c.content_digest=OLD.origin_content_digest) THEN RAISE(ABORT,'origin envelope changed') END;
      SELECT CASE WHEN OLD.parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=OLD.user_scope_id AND p.materialization_id=OLD.parent_materialization_id AND p.materialization_state='applied' AND p.vehicle_alias_id=OLD.vehicle_alias_id AND p.graph_generation=OLD.graph_generation AND p.canonical_vehicle_id=OLD.canonical_vehicle_id AND p.origin_device_identity_id=OLD.origin_device_identity_id AND p.origin_vehicle_id=OLD.origin_vehicle_id) THEN RAISE(ABORT,'parent not applied') END;
      SELECT CASE WHEN OLD.parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=OLD.user_scope_id AND p.materialization_id=OLD.parent_materialization_id AND p.materialization_state='applied' AND p.entity_kind=OLD.origin_parent_entity_kind AND p.origin_entity_id=OLD.origin_parent_entity_id AND p.materialized_entity_id=OLD.materialized_parent_entity_id AND p.vehicle_alias_id=OLD.vehicle_alias_id AND p.graph_generation=OLD.graph_generation AND p.canonical_vehicle_id=OLD.canonical_vehicle_id AND p.origin_device_identity_id=OLD.origin_device_identity_id AND p.origin_vehicle_id=OLD.origin_vehicle_id) THEN RAISE(ABORT,'direct parent not semantically applied') END;
      SELECT CASE WHEN OLD.secondary_parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=OLD.user_scope_id AND p.materialization_id=OLD.secondary_parent_materialization_id AND p.materialization_state='applied' AND p.entity_kind=OLD.origin_secondary_parent_entity_kind AND p.origin_entity_id=OLD.origin_secondary_parent_entity_id AND p.materialized_entity_id=OLD.materialized_secondary_parent_entity_id AND p.vehicle_alias_id=OLD.vehicle_alias_id AND p.graph_generation=OLD.graph_generation AND p.canonical_vehicle_id=OLD.canonical_vehicle_id AND p.origin_device_identity_id=OLD.origin_device_identity_id AND p.origin_vehicle_id=OLD.origin_vehicle_id) THEN RAISE(ABORT,'secondary parent not semantically applied') END;
      SELECT CASE WHEN OLD.tertiary_parent_materialization_id IS NOT NULL AND NOT EXISTS(SELECT 1 FROM origin_entity_materializations p WHERE p.user_scope_id=OLD.user_scope_id AND p.materialization_id=OLD.tertiary_parent_materialization_id AND p.materialization_state='applied' AND p.entity_kind=OLD.origin_tertiary_parent_entity_kind AND p.origin_entity_id=OLD.origin_tertiary_parent_entity_id AND p.materialized_entity_id=OLD.materialized_tertiary_parent_entity_id AND p.vehicle_alias_id=OLD.vehicle_alias_id AND p.graph_generation=OLD.graph_generation AND p.canonical_vehicle_id=OLD.canonical_vehicle_id AND p.origin_device_identity_id=OLD.origin_device_identity_id AND p.origin_vehicle_id=OLD.origin_vehicle_id) THEN RAISE(ABORT,'tertiary parent not semantically applied') END;
    END;
    CREATE TRIGGER materialization_digest_immutable BEFORE UPDATE ON origin_entity_materializations WHEN NEW.materialized_content_digest<>OLD.materialized_content_digest OR NEW.origin_content_digest<>OLD.origin_content_digest BEGIN SELECT RAISE(ABORT,'materialization digest is immutable'); END;

    CREATE TRIGGER segments_complete_guard BEFORE UPDATE OF transfer_state ON chunk_transfers WHEN NEW.transfer_state='segments_complete' AND (NOT EXISTS(SELECT 1 FROM chunk_transfer_segments s WHERE s.user_scope_id=OLD.user_scope_id AND s.chunk_transfer_id=OLD.chunk_transfer_id) OR EXISTS(SELECT 1 FROM chunk_transfer_segments s WHERE s.user_scope_id=OLD.user_scope_id AND s.chunk_transfer_id=OLD.chunk_transfer_id AND s.segment_state<>'verified') OR (SELECT MIN(byte_offset) FROM chunk_transfer_segments s WHERE s.user_scope_id=OLD.user_scope_id AND s.chunk_transfer_id=OLD.chunk_transfer_id)<>0 OR (SELECT SUM(byte_length) FROM chunk_transfer_segments s WHERE s.user_scope_id=OLD.user_scope_id AND s.chunk_transfer_id=OLD.chunk_transfer_id)<>OLD.ciphertext_size OR EXISTS(SELECT 1 FROM chunk_transfer_segments s WHERE s.user_scope_id=OLD.user_scope_id AND s.chunk_transfer_id=OLD.chunk_transfer_id AND s.segment_index>0 AND NOT EXISTS(SELECT 1 FROM chunk_transfer_segments p WHERE p.user_scope_id=s.user_scope_id AND p.chunk_transfer_id=s.chunk_transfer_id AND p.segment_index=s.segment_index-1 AND p.byte_offset+p.byte_length=s.byte_offset))) BEGIN SELECT RAISE(ABORT,'segments not durable'); END;
    CREATE TRIGGER chunk_transfer_transition_guard BEFORE UPDATE OF transfer_state ON chunk_transfers WHEN NOT((OLD.transfer_state='pending' AND NEW.transfer_state IN ('receiving','quarantined')) OR (OLD.transfer_state='receiving' AND NEW.transfer_state IN ('segments_complete','quarantined')) OR (OLD.transfer_state='segments_complete' AND NEW.transfer_state IN ('verified','quarantined')) OR (OLD.transfer_state='verified' AND NEW.transfer_state IN ('file_durable','quarantined')) OR (OLD.transfer_state='file_durable' AND NEW.transfer_state IN ('cataloged','quarantined'))) BEGIN SELECT RAISE(ABORT,'invalid chunk transfer transition'); END;
    CREATE TRIGGER segment_transition_guard BEFORE UPDATE OF segment_state ON chunk_transfer_segments WHEN NOT((OLD.segment_state='expected' AND NEW.segment_state='received') OR (OLD.segment_state='received' AND NEW.segment_state='verified')) BEGIN SELECT RAISE(ABORT,'invalid segment transition'); END;
    CREATE TRIGGER session_durable_guard BEFORE UPDATE OF transfer_state ON session_transfers WHEN NEW.transfer_state='durable' AND ((SELECT COUNT(*) FROM chunk_transfers c WHERE c.user_scope_id=OLD.user_scope_id AND c.session_transfer_id=OLD.session_transfer_id AND c.transfer_state='cataloged')<>OLD.expected_chunk_count OR COALESCE((SELECT SUM(ciphertext_size) FROM chunk_transfers c WHERE c.user_scope_id=OLD.user_scope_id AND c.session_transfer_id=OLD.session_transfer_id AND c.transfer_state='cataloged'),0)<>OLD.expected_ciphertext_bytes) BEGIN SELECT RAISE(ABORT,'durable ack conditions not met'); END;
    CREATE TRIGGER session_transfer_transition_guard BEFORE UPDATE OF transfer_state ON session_transfers WHEN NOT((OLD.transfer_state='manifest_pending' AND NEW.transfer_state IN ('transferring','retryable','blocked')) OR (OLD.transfer_state='transferring' AND NEW.transfer_state IN ('verifying','retryable','blocked')) OR (OLD.transfer_state='verifying' AND NEW.transfer_state IN ('durable','retryable','blocked')) OR (OLD.transfer_state='durable' AND NEW.transfer_state='acknowledged') OR (OLD.transfer_state='retryable' AND NEW.transfer_state IN ('manifest_pending','transferring','verifying'))) BEGIN SELECT RAISE(ABORT,'invalid session transfer transition'); END;

    CREATE TRIGGER wrapped_key_local_recipient BEFORE INSERT ON wrapped_key_receipts WHEN NOT EXISTS(SELECT 1 FROM local_device_identity l WHERE l.user_scope_id=NEW.user_scope_id AND l.device_identity_id=NEW.recipient_identity_id) BEGIN SELECT RAISE(ABORT,'wrong key recipient'); END;
    CREATE TRIGGER wrapped_key_verify_trust BEFORE UPDATE OF receipt_state ON wrapped_key_receipts WHEN NEW.receipt_state='verified' AND NOT EXISTS(SELECT 1 FROM device_trust_records t WHERE t.user_scope_id=OLD.user_scope_id AND t.peer_identity_id=OLD.sender_identity_id AND t.trust_state='trusted' AND t.trust_generation=OLD.trust_generation) BEGIN SELECT RAISE(ABORT,'stale key trust'); END;

    CREATE VIEW active_or_local_vehicle_identification_scans AS SELECT b.* FROM vehicle_identification_scans b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='vehicle_identification_scan' AND m.materialized_entity_id=b.scan_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='vehicle_identification_scan' AND m.materialized_entity_id=b.scan_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_vehicle_identifiers AS SELECT b.* FROM vehicle_identifiers b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='vehicle_identifier' AND m.materialized_entity_id=b.identifier_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='vehicle_identifier' AND m.materialized_entity_id=b.identifier_id AND m.materialization_state='applied' AND (m.materialization_result_kind='inserted_projection' OR (m.materialization_result_kind='linked_existing_duplicate' AND m.canonical_vehicle_id=b.vehicle_id AND m.materialized_identifier_kind=b.identifier_kind AND m.materialized_identifier_digest_key_version=b.digest_key_version AND m.materialized_identifier_lookup_digest=b.lookup_digest)));
    CREATE VIEW active_or_local_ecu_observations AS SELECT b.* FROM ecu_observations b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='ecu_observation' AND m.materialized_entity_id=b.ecu_observation_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='ecu_observation' AND m.materialized_entity_id=b.ecu_observation_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_ecu_identification_values AS SELECT b.* FROM ecu_identification_values b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='ecu_identification_value' AND m.materialized_entity_id=b.identification_value_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='ecu_identification_value' AND m.materialized_entity_id=b.identification_value_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_acquisition_sessions AS SELECT b.* FROM acquisition_sessions b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_session' AND m.materialized_entity_id=b.session_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_session' AND m.materialized_entity_id=b.session_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_acquisition_streams AS SELECT b.* FROM acquisition_streams b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_stream' AND m.materialized_entity_id=b.stream_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_stream' AND m.materialized_entity_id=b.stream_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_clock_epochs AS SELECT b.* FROM clock_epochs b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='clock_epoch' AND m.materialized_entity_id=b.clock_epoch_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='clock_epoch' AND m.materialized_entity_id=b.clock_epoch_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_acquisition_gaps AS SELECT b.* FROM acquisition_gaps b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_gap' AND m.materialized_entity_id=b.gap_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='acquisition_gap' AND m.materialized_entity_id=b.gap_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');
    CREATE VIEW active_or_local_log_chunks AS SELECT b.* FROM log_chunks b WHERE NOT EXISTS(SELECT 1 FROM origin_entity_materializations m WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='log_chunk_manifest' AND m.materialized_entity_id=b.chunk_id AND m.materialization_result_kind='inserted_projection') OR EXISTS(SELECT 1 FROM origin_entity_materializations m JOIN vehicle_id_aliases a ON a.user_scope_id=m.user_scope_id AND a.vehicle_alias_id=m.vehicle_alias_id AND a.alias_revision=m.graph_generation AND a.mapping_state='active' WHERE m.user_scope_id=b.user_scope_id AND m.entity_kind='log_chunk_manifest' AND m.materialized_entity_id=b.chunk_id AND m.materialization_result_kind='inserted_projection' AND m.materialization_state='applied');

    CREATE TRIGGER conflict_candidates_no_update BEFORE UPDATE ON sync_conflict_candidates BEGIN SELECT RAISE(ABORT,'conflict candidates are immutable'); END;
    CREATE TRIGGER conflict_candidates_no_delete BEFORE DELETE ON sync_conflict_candidates BEGIN SELECT RAISE(ABORT,'conflict candidates cannot be deleted'); END;
    CREATE TRIGGER segments_no_delete BEFORE DELETE ON chunk_transfer_segments BEGIN SELECT RAISE(ABORT,'segments cannot be deleted'); END;
    CREATE TRIGGER aliases_no_delete BEFORE DELETE ON vehicle_id_aliases BEGIN SELECT RAISE(ABORT,'aliases cannot be deleted'); END;
    CREATE TRIGGER materializations_no_delete BEFORE DELETE ON origin_entity_materializations BEGIN SELECT RAISE(ABORT,'materializations cannot be deleted'); END;
    CREATE TRIGGER quarantine_no_delete BEFORE DELETE ON sync_quarantine_items BEGIN SELECT RAISE(ABORT,'quarantine cannot be deleted'); END;
    """
}
